#[cfg(test)]
mod tests {
    use super::*;
    use crate::config::Config;
    use pretty_assertions::{assert_eq, assert_str_eq};

    #[tokio::test]
    async fn test_backend_arg() {
        let _config = Config::get().await.unwrap();
        let t = |s: &str, full, tool_name, t| {
            let fa: BackendArg = s.into();
            assert_str_eq!(full, fa.full());
            assert_str_eq!(tool_name, fa.tool_name);
            assert_eq!(t, fa.backend_type());
        };
        #[cfg(unix)]
        let asdf = |s, full, name| t(s, full, name, BackendType::Asdf);
        let cargo = |s, full, name| t(s, full, name, BackendType::Cargo);
        // let core = |s, full, name| t(s, full, name, BackendType::Core);
        let npm = |s, full, name| t(s, full, name, BackendType::Npm);
        let vfox = |s, full, name| t(s, full, name, BackendType::Vfox);

        #[cfg(unix)]
        {
            asdf("asdf:clojure", "asdf:clojure", "clojure");
            vfox("clojure", "vfox:jdx/vfox-clojure", "clojure");
        }
        cargo("cargo:eza", "cargo:eza", "eza");
        t("dotnet-core", "core:dotnet", "dotnet", BackendType::Core);
        // core("node", "node", "node");
        npm("npm:@antfu/ni", "npm:@antfu/ni", "@antfu/ni");
        npm("npm:prettier", "npm:prettier", "prettier");
        vfox(
            "vfox:version-fox/vfox-nodejs",
            "vfox:version-fox/vfox-nodejs",
            "version-fox/vfox-nodejs",
        );
    }

    #[tokio::test]
    async fn test_bare_package_backend_names_are_not_implicit_tools() {
        let _config = Config::get().await.unwrap();

        for name in ["cargo", "gem"] {
            let fa: BackendArg = name.into();
            assert_str_eq!(name, fa.full());
            assert_eq!(BackendType::Unknown, fa.backend_type());
        }

        let fa: BackendArg = "cargo:ripgrep".into();
        assert_eq!(BackendType::Cargo, fa.backend_type());

        let fa: BackendArg = "gem:bashly".into();
        assert_eq!(BackendType::Gem, fa.backend_type());

        let fa: BackendArg = "npm:npm".into();
        assert_str_eq!("npm:npm", fa.full());
        assert_eq!(BackendType::Npm, fa.backend_type());
    }

    #[tokio::test]
    async fn test_bare_npm_uses_registry_tool() {
        let _config = Config::get().await.unwrap();

        let fa: BackendArg = "npm".into();
        #[cfg(windows)]
        {
            assert_str_eq!("npm:npm", fa.full());
            assert_eq!(BackendType::Npm, fa.backend_type());
        }
        #[cfg(not(windows))]
        {
            assert_str_eq!("aqua:npm/cli", fa.full());
            assert_eq!(BackendType::Aqua, fa.backend_type());
        }
    }

    #[tokio::test]
    async fn test_backend_arg_pathname() {
        let _config = Config::get().await.unwrap();
        let t = |s: &str, expected| {
            let fa: BackendArg = s.into();
            let actual = fa.installs_path.to_string_lossy();
            let expected = dirs::INSTALLS.join(expected);
            assert_str_eq!(actual, expected.to_string_lossy());
        };
        t("asdf:node", "asdf-node");
        t("node", "node");
        for plugin in backend::list() {
            let is_core = CORE_PLUGINS.contains_key(plugin.id());
            let plugin_type = plugin.get_plugin_type();

            if is_core && matches!(plugin_type, Some(PluginType::Asdf | PluginType::Vfox)) {
                self.warnings
                    .push(format!("plugin {} overrides a core plugin", &plugin.id()));
            }
        }
    }

    fn analyze_backend_mismatches(&mut self) {
        for (short, ist) in install_state::list_tools().iter() {
            // Skip plugin-based tools (they use the plugin as backend)
            if install_state::get_plugin_type(short).is_some() {
                continue;
            }

            // Get stored backend, skip if none
            let Some(stored_full) = &ist.full else {
                continue;
            };

            // Get registry entry, skip if not in registry
            let Some(rt) = REGISTRY.get(short.as_str()) else {
                continue;
            };

            // Get recommended backend for current platform
            let backends = rt.backends();
            let Some(registry_full) = backends.first() else {
                continue;
            };

            // Strip options for comparison (e.g., "github:repo[exe=bin]" -> "github:repo")
            let stored_stripped = stored_full.split('[').next().unwrap_or(stored_full);
            let registry_stripped = registry_full.split('[').next().unwrap_or(registry_full);

            // Compare backends
            if stored_stripped != registry_stripped {
                let msg = if ist.explicit_backend {
                    formatdoc!(
                        r#"tool '{short}' installed with explicit backend '{stored_full}'
                           differs from registry recommendation '{registry_full}'.
                           To switch: mise uninstall --all {short} && mise install {short}"#
                    )
                } else {
                    formatdoc!(
                        r#"tool '{short}' installed with backend '{stored_full}'
                           but registry now recommends '{registry_full}'.
                           To migrate: mise uninstall --all {short} && mise install {short}"#
                    )
                };
                self.warnings.push(msg);
            }
        }
    }

    async fn paths(&mut self, ts: &Toolset) -> eyre::Result<Vec<PathBuf>> {
        let config = Config::get().await?;
        let env = ts.full_env(&config).await?;
        let path = env
            .get(&*PATH_KEY)
            .ok_or_else(|| eyre::eyre!("Path not found"))?;
        Ok(split_paths(path).collect())
    }
